SELECT * FROM user_coupon
WHERE user_id = #{userId} AND deleted = 0
AND store_id = #{storeId}
AND status = #{status}
ORDER BY id DESC

mapper.sql:
uc.deleted = 0
AND uc.store_id = #{storeId}
AND uc.user_id = #{userId}
AND uc.status = #{status}

mapper.select:
SELECT crr.*, uc.store_id, uc.coupon_no, uc.coupon_name, u.nickname, u.phone
FROM coupon_redeem_request crr
LEFT JOIN user_coupon uc ON uc.id = crr.user_coupon_id AND uc.deleted = 0
LEFT JOIN `user` u ON u.id = crr.user_id AND u.deleted = 0
WHERE crr.deleted = 0
AND uc.store_id = #{storeId}
AND crr.status = #{status}
ORDER BY crr.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM coupon_redeem_request crr
LEFT JOIN user_coupon uc ON uc.id = crr.user_coupon_id AND uc.deleted = 0
WHERE crr.deleted = 0
AND uc.store_id = #{storeId}
AND crr.status = #{status}
